export enum UserRole {
  ADMIN = 'ADMIN',
  STAFF = 'STAFF',
  RECEPTION = 'RECEPTION'
}

export enum TokenStatus {
  WAITING = 'WAITING',
  CALLED = 'CALLED',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED'
}

export interface User {
  id: number;
  name: string;
  email: string;
  role: UserRole;
}

export interface Service {
  id: number;
  serviceName: string;
  description: string;
  averageTimeMinutes: number;
  status: boolean;
}

export interface Counter {
  id: number;
  counterName: string;
  serviceId: number;
  status: boolean;
}

export interface Token {
  id: number;
  tokenNumber: string;
  serviceId: number;
  customerName: string;
  phone: string;
  status: TokenStatus;
  createdAt: string;
  calledAt?: string;
  completedAt?: string;
  counterId?: number;
}

export interface QueueDisplayItem {
  tokenNumber: string;
  counterName: string;
  status: TokenStatus;
}

import React from 'react';
import { 
  LayoutDashboard, 
  Settings, 
  Monitor, 
  Ticket, 
  Users, 
  BarChart3, 
  LogOut,
  Layers
} from 'lucide-react';

export const COLORS = {
  primary: '#FFB347', // Light Orange
  secondary: '#1A1A1A', // Matt Black
  accent: '#F5F5F5', // Soft Gray
};

export const NAVIGATION_ITEMS = [
  { path: '/admin', label: 'Dashboard', icon: <LayoutDashboard size={20} />, roles: ['ADMIN'] },
  { path: '/services', label: 'Services', icon: <Layers size={20} />, roles: ['ADMIN'] },
  { path: '/counters', label: 'Counters', icon: <Settings size={20} />, roles: ['ADMIN'] },
  { path: '/generate-token', label: 'New Token', icon: <Ticket size={20} />, roles: ['ADMIN', 'RECEPTION'] },
  { path: '/staff-panel', label: 'Staff Panel', icon: <Users size={20} />, roles: ['ADMIN', 'STAFF'] },
  { path: '/display', label: 'Live Queue', icon: <Monitor size={20} />, roles: ['ADMIN', 'STAFF', 'RECEPTION'] },
  { path: '/reports', label: 'Reports', icon: <BarChart3 size={20} />, roles: ['ADMIN'] },
];

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, Link, useLocation } from 'react-router-dom';
import { User, UserRole } from './types';
import Login from './pages/Login';
import AdminDashboard from './pages/AdminDashboard';
import ManageServices from './pages/ManageServices';
import ManageCounters from './pages/ManageCounters';
import GenerateToken from './pages/GenerateToken';
import QueueDisplay from './pages/QueueDisplay';
import StaffPanel from './pages/StaffPanel';
import Reports from './pages/Reports';
import Layout from './components/Layout';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('user');
    return saved ? JSON.parse(saved) : null;
  });

  const handleLogin = (userData: User) => {
    setUser(userData);
    localStorage.setItem('user', JSON.stringify(userData));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('user');
  };

  return (
    <HashRouter>
      <Routes>
        <Route 
          path="/login" 
          element={!user ? <Login onLogin={handleLogin} /> : <Navigate to={user.role === UserRole.ADMIN ? '/admin' : user.role === UserRole.STAFF ? '/staff-panel' : '/generate-token'} />} 
        />

        {/* Public Route */}
        <Route path="/display" element={<QueueDisplay />} />

        {/* Protected Routes */}
        <Route element={<Layout user={user} onLogout={handleLogout} />}>
          <Route path="/admin" element={user?.role === UserRole.ADMIN ? <AdminDashboard /> : <Navigate to="/login" />} />
          <Route path="/services" element={user?.role === UserRole.ADMIN ? <ManageServices /> : <Navigate to="/login" />} />
          <Route path="/counters" element={user?.role === UserRole.ADMIN ? <ManageCounters /> : <Navigate to="/login" />} />
          <Route path="/generate-token" element={(user?.role === UserRole.ADMIN || user?.role === UserRole.RECEPTION) ? <GenerateToken /> : <Navigate to="/login" />} />
          <Route path="/staff-panel" element={(user?.role === UserRole.ADMIN || user?.role === UserRole.STAFF) ? <StaffPanel user={user!} /> : <Navigate to="/login" />} />
          <Route path="/reports" element={user?.role === UserRole.ADMIN ? <Reports /> : <Navigate to="/login" />} />
        </Route>

        <Route path="/" element={<Navigate to={user ? (user.role === UserRole.ADMIN ? '/admin' : '/staff-panel') : '/login'} />} />
      </Routes>
    </HashRouter>
  );
};

export default App;

