              <User className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input
                type="text" required
                className="w-full pl-10 pr-4 py-3 bg-soft-gray rounded-lg border-none focus:ring-2 focus:ring-light-orange transition-all"
