    }

    @GetMapping("/active")
    public List<Token> getActiveTokens() {
        return tokenRepository.findByStatusIn(List.of(TokenStatus.WAITING, TokenStatus.CALLED));
    }

    @PostMapping("/call-next/{counterId}")
