import React, { useState, useEffect } from 'react';
import { mockApi } from '../services/mockApi';
import { Service, Token } from '../types';
import { Ticket, User, Phone, CheckCircle } from 'lucide-react';

const GenerateToken: React.FC = () => {
  const [services, setServices] = useState<Service[]>([]);
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [selectedServiceId, setSelectedServiceId] = useState<number | ''>('');
  const [generatedToken, setGeneratedToken] = useState<Token | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    mockApi.getServices().then(setServices);
  }, []);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedServiceId) return;

    setLoading(true);
    try {
      const token = await mockApi.generateToken({
        serviceId: Number(selectedServiceId),
        name,
        phone
      });
      setGeneratedToken(token);
      setName('');
      setPhone('');
      setSelectedServiceId('');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div>
        <h1 className="text-3xl font-bold text-matt-black text-center">Token Registration</h1>
        <p className="text-gray-500 text-center">Register a new visitor for service</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-start">
        <form onSubmit={handleGenerate} className="bg-white p-8 rounded-2xl shadow-sm border border-gray-100 space-y-6">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">Visitor Name</label>
            <div className="relative">
              <User className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input
                type="text" required
                className="w-full pl-10 pr-4 py-3 bg-soft-gray rounded-lg border-none focus:ring-2 focus:ring-light-orange transition-all text-matt-black"
                placeholder="Full Name"
                value={name}
                onChange={e => setName(e.target.value)}
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">Phone Number</label>
            <div className="relative">
              <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input
                type="tel" required
                className="w-full pl-10 pr-4 py-3 bg-soft-gray rounded-lg border-none focus:ring-2 focus:ring-light-orange transition-all text-matt-black"
                placeholder="Contact Number"
                value={phone}
                onChange={e => setPhone(e.target.value)}
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">Required Service</label>
            <div className="relative">
              <select
                required
                className="w-full px-4 py-3 bg-soft-gray rounded-lg border-none focus:ring-2 focus:ring-light-orange transition-all appearance-none text-matt-black"
                value={selectedServiceId}
                onChange={e => setSelectedServiceId(e.target.value ? parseInt(e.target.value) : '')}
              >
                <option value="">Select Service</option>
                {services.map(s => (
                  <option key={s.id} value={s.id}>{s.serviceName} ({s.averageTimeMinutes}m)</option>
                ))}
              </select>
              <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-4 text-gray-500">
                <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
              </div>
            </div>
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-matt-black text-white font-bold py-4 rounded-xl flex items-center justify-center space-x-2 hover:bg-black transition-all active:scale-[0.98] disabled:opacity-50"
          >
            <Ticket size={20} />
            <span>{loading ? 'Processing...' : 'Generate Token'}</span>
          </button>
        </form>

        <div className="flex flex-col items-center justify-center h-full">
          {generatedToken ? (
            <div className="bg-white w-full p-8 rounded-2xl shadow-xl border-4 border-light-orange relative overflow-hidden text-center transform animate-in zoom-in duration-300">
               <div className="absolute top-0 right-0 p-4 opacity-10">
                 <Ticket size={120} />
               </div>
               <div className="flex justify-center mb-4">
                 <div className="bg-green-100 text-green-600 p-3 rounded-full">
                    <CheckCircle size={32} />
                 </div>
               </div>
               <p className="text-gray-500 font-semibold uppercase tracking-widest text-sm mb-1">Your Token Number</p>
               <h2 className="text-6xl font-black text-matt-black mb-6">{generatedToken.tokenNumber}</h2>

               <div className="border-t border-dashed border-gray-200 py-4 mb-4 text-left">
                  <div className="flex justify-between mb-2">
                    <span className="text-gray-500 text-sm">Customer</span>
                    <span className="font-bold text-matt-black">{generatedToken.customerName}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500 text-sm">Date</span>
                    <span className="font-bold text-matt-black">{new Date(generatedToken.createdAt).toLocaleTimeString()}</span>
                  </div>
               </div>

               <button 
                onClick={() => window.print()} 
                className="w-full py-2 bg-gray-100 text-gray-600 rounded-lg hover:bg-gray-200 font-bold transition-colors"
               >
                 Print Ticket
               </button>
            </div>
          ) : (
            <div className="bg-gray-50 border-2 border-dashed border-gray-200 w-full p-12 rounded-2xl flex flex-col items-center justify-center text-gray-400">
              <Ticket size={64} className="mb-4 opacity-50" />
              <p className="text-center">New token details will appear here after submission</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default GenerateToken;

