import React, { useState, useEffect } from 'react';
import { mockApi } from '../services/mockApi';
import { User, Token, Counter, TokenStatus } from '../types';
import { Play, CheckCircle, XCircle, Users, BellRing, UserCheck, ChevronDown, PlusCircle, User as UserIcon } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

interface StaffPanelProps {
  user: User;
}

const StaffPanel: React.FC<StaffPanelProps> = ({ user }) => {
  const navigate = useNavigate();
  const [activeCounter, setActiveCounter] = useState<Counter | null>(null);
  const [allCounters, setAllCounters] = useState<Counter[]>([]);
  const [currentToken, setCurrentToken] = useState<Token | null>(null);
  const [waitingTokens, setWaitingTokens] = useState<Token[]>([]);
  const [loading, setLoading] = useState(false);

  // Initial load of counters
  useEffect(() => {
    const initCounters = async () => {
      const counters = await mockApi.getCounters();
      setAllCounters(counters);

      // Default selection logic if none selected yet
      if (!activeCounter) {
        let defaultCounter = counters[0];
        if (user.role === 'STAFF') {
            defaultCounter = user.id === 2 ? counters[0] : counters[1]; 
        } else if (user.role === 'RECEPTION') {
            defaultCounter = counters[2];
        }
        setActiveCounter(defaultCounter);
      }
    };
    initCounters();
  }, [user]);

  const loadQueueData = async () => {
    if (!activeCounter) return;

    const t = await mockApi.getActiveTokens();

    // Find if current counter is serving someone
    const serving = t.find(token => token.counterId === activeCounter.id && token.status === TokenStatus.CALLED);
    setCurrentToken(serving || null);

    // Get waiting list for this counter's service
    const waiting = t.filter(token => token.serviceId === activeCounter.serviceId && token.status === TokenStatus.WAITING);
    setWaitingTokens(waiting);
  };

  // Poll for queue updates
  useEffect(() => {
    loadQueueData();
    const int = setInterval(loadQueueData, 5000);
    return () => clearInterval(int);
  }, [activeCounter]);

  const handleCounterChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const counterId = parseInt(e.target.value);
    const selected = allCounters.find(c => c.id === counterId);
    if (selected) {
      setActiveCounter(selected);
      setCurrentToken(null); // Reset local state when switching counters
    }
  };

  const handleCallNext = async () => {
    if (!activeCounter) return;
    setLoading(true);
    try {
      const next = await mockApi.callNextToken(activeCounter.id);
      setCurrentToken(next);
      loadQueueData();
    } catch (err: any) {
      alert(err || "No more tokens");
    } finally {
      setLoading(false);
    }
  };

  const handleCallSpecific = async (tokenId: number) => {
    if (!activeCounter) return;
    if (currentToken) {
        alert("Please complete or cancel the current visitor before calling a new one.");
        return;
    }
    setLoading(true);
    try {
      const token = await mockApi.callSpecificToken(tokenId, activeCounter.id);
      setCurrentToken(token);
      loadQueueData();
    } catch (err: any) {
      alert(err || "Error calling token");
    } finally {
      setLoading(false);
    }
  };

  const handleComplete = async () => {
    if (!currentToken) return;
    await mockApi.completeToken(currentToken.id);
    setCurrentToken(null);
    loadQueueData();
  };

  const handleCancel = async () => {
    if (!currentToken) return;
    await mockApi.cancelToken(currentToken.id);
    setCurrentToken(null);
    loadQueueData();
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 pb-20">
      {/* Top Professional Header - User Info at the Top */}
      <div className="bg-matt-black text-white p-6 rounded-[2rem] shadow-2xl flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="flex items-center space-x-5">
           <div className="w-14 h-14 bg-light-orange rounded-2xl flex items-center justify-center text-matt-black">
              <UserIcon size={28} />
           </div>
           <div>
              <p className="text-gray-400 text-xs font-black uppercase tracking-widest">Active Operator</p>
              <h1 className="text-2xl font-black">{user.name}</h1>
           </div>
           <div className="hidden md:block h-10 w-px bg-white/10 mx-2"></div>
           <div className="hidden md:block">
              <p className="text-gray-400 text-xs font-black uppercase tracking-widest mb-1">Station Assignment</p>
              <div className="relative inline-block">
                <select 
                  value={activeCounter?.id || ''} 
                  onChange={handleCounterChange}
                  className="appearance-none bg-white/5 border border-white/10 px-4 py-1 pr-10 rounded-xl font-bold text-light-orange focus:ring-2 focus:ring-light-orange outline-none transition-all cursor-pointer hover:bg-white/10"
                >
                  {allCounters.map(c => (
                    <option key={c.id} value={c.id} className="text-matt-black">{c.counterName}</option>
                  ))}
                </select>
                <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-gray-400">
                  <ChevronDown size={14} />
                </div>
              </div>
           </div>
        </div>

        <div className="flex items-center space-x-4">
           {/* New Token Quick Action */}
           <button 
             onClick={() => navigate('/generate-token')}
             className="bg-light-orange text-matt-black px-6 py-4 rounded-2xl font-black flex items-center space-x-3 hover:scale-105 transition-all shadow-lg active:scale-95 whitespace-nowrap"
           >
              <PlusCircle size={24} />
              <span>NEW TOKEN</span>
           </button>
           <div className="bg-white/5 border border-white/10 px-6 py-3 rounded-2xl hidden lg:flex items-center space-x-4">
              <div className="text-right">
                 <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest leading-tight">Total Waiting</p>
                 <p className="text-2xl font-black text-white">{waitingTokens.length}</p>
              </div>
              <div className="w-10 h-10 bg-blue-500/20 text-blue-400 rounded-xl flex items-center justify-center">
                 <Users size={20} />
              </div>
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        {/* Main Action Area */}
        <div className="lg:col-span-3 space-y-6">
          {currentToken ? (
            <div className="bg-white rounded-[3rem] p-16 shadow-xl border-4 border-light-orange flex flex-col items-center text-center space-y-10 transform animate-in zoom-in duration-300 relative overflow-hidden">
               {/* Background Watermark */}
               <div className="absolute -top-10 -right-10 text-gray-50 opacity-[0.03] select-none pointer-events-none">
                  <p className="text-[30rem] font-black leading-none">{currentToken.tokenNumber}</p>
               </div>

               <div className="space-y-4 relative z-10">
                 <span className="bg-orange-100 text-orange-600 px-6 py-2 rounded-full text-sm font-black uppercase tracking-[0.2em] animate-pulse">Now Serving Visitor</span>
                 {/* Increased Token Display Size */}
                 <h2 className="text-[14rem] md:text-[18rem] font-black text-matt-black leading-none tracking-tighter drop-shadow-sm">{currentToken.tokenNumber}</h2>
               </div>

               <div className="w-full max-w-2xl grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10">
                  <div className="text-left bg-soft-gray p-8 rounded-[2rem] border border-gray-100">
                     <p className="text-xs text-gray-400 font-black uppercase tracking-[0.2em] mb-2">Patient Name</p>
                     <p className="font-black text-matt-black truncate text-3xl">{currentToken.customerName}</p>
                  </div>
                  <div className="text-left bg-soft-gray p-8 rounded-[2rem] border border-gray-100">
                     <p className="text-xs text-gray-400 font-black uppercase tracking-[0.2em] mb-2">Check-in Time</p>
                     <p className="font-black text-matt-black text-3xl">{new Date(currentToken.createdAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                  </div>
               </div>

               <div className="grid grid-cols-2 gap-6 w-full max-w-xl pt-6 relative z-10">
                  <button 
                    onClick={handleComplete}
                    className="bg-green-500 text-white font-black py-8 rounded-3xl flex flex-col items-center justify-center space-y-3 hover:bg-green-600 transition-all hover:shadow-2xl active:scale-95 text-xl"
                  >
                    <CheckCircle size={48} />
                    <span>COMPLETE VISIT</span>
                  </button>
                  <button 
                    onClick={handleCancel}
                    className="bg-red-500 text-white font-black py-8 rounded-3xl flex flex-col items-center justify-center space-y-3 hover:bg-red-600 transition-all hover:shadow-2xl active:scale-95 text-xl"
                  >
                    <XCircle size={48} />
                    <span>CANCEL / NO-SHOW</span>
                  </button>
               </div>
            </div>
          ) : (
            <div className="bg-white rounded-[3rem] p-24 shadow-sm border-4 border-dashed border-gray-100 flex flex-col items-center text-center space-y-8 min-h-[600px] justify-center">
               <div className="w-32 h-32 bg-soft-gray rounded-[2.5rem] flex items-center justify-center text-gray-200">
                  <Play size={64} fill="currentColor" />
               </div>
               <div>
                  <h2 className="text-4xl font-black text-gray-300">STATION IDLE</h2>
                  <p className="text-gray-400 mt-4 text-lg max-w-sm mx-auto font-medium">Ready to serve the next visitor at {activeCounter?.counterName}.</p>
               </div>
               <button 
                 onClick={handleCallNext}
                 disabled={loading || waitingTokens.length === 0}
                 className="bg-matt-black text-white px-16 py-8 rounded-[2.5rem] font-black text-3xl hover:bg-black transition-all shadow-2xl disabled:opacity-30 disabled:cursor-not-allowed transform active:scale-95 flex items-center space-x-6 uppercase tracking-[0.2em]"
               >
                 <BellRing size={36} className="text-light-orange" />
                 <span>Call Next</span>
               </button>
            </div>
          )}
        </div>

        {/* Sidebar: Waiting Queue */}
        <div className="bg-white rounded-[3rem] border border-gray-100 shadow-sm flex flex-col overflow-hidden max-h-[850px]">
            <div className="p-8 border-b border-gray-50 bg-soft-gray flex justify-between items-center">
                <h3 className="font-black text-matt-black uppercase tracking-[0.15em] text-sm">UP NEXT</h3>
                <span className="bg-matt-black text-white text-xs font-black px-3 py-1.5 rounded-xl">{waitingTokens.length}</span>
            </div>
            <div className="flex-1 overflow-auto p-6 space-y-4">
                {waitingTokens.map(token => (
                    <div key={token.id} className="group p-6 bg-white border border-gray-100 rounded-[2rem] hover:border-light-orange hover:shadow-lg transition-all flex flex-col space-y-4">
                        <div className="flex justify-between items-start">
                            <div>
                                <p className="text-4xl font-black text-matt-black leading-tight tracking-tight">{token.tokenNumber}</p>
                                <p className="text-sm font-bold text-gray-400 mt-1 truncate max-w-[150px]">{token.customerName}</p>
                            </div>
                        </div>
                        <button 
                            onClick={() => handleCallSpecific(token.id)}
                            disabled={loading || !!currentToken}
                            className="w-full bg-soft-gray text-matt-black py-4 rounded-2xl group-hover:bg-light-orange transition-all disabled:opacity-20 flex items-center justify-center space-x-3"
                        >
                            <UserCheck size={20} />
                            <span className="font-black text-xs uppercase tracking-widest">Process This Token</span>
                        </button>
                    </div>
                ))}
                {waitingTokens.length === 0 && (
                    <div className="flex flex-col items-center justify-center py-20 text-gray-300 opacity-50">
                        <Users size={64} className="mb-6" />
                        <p className="font-black text-xl italic uppercase tracking-widest">No Waiting</p>
                    </div>
                )}
            </div>
            <div className="p-8 bg-orange-50/50 border-t border-orange-100/50 text-xs text-orange-800/60 font-black uppercase tracking-widest text-center">
                Automated Sync Active
            </div>
        </div>
      </div>
    </div>
  );
};

